local LBloodStick = LxRequire("LApp.gameplay.Common.LBloodStick")

local typeSpineClick = typeof(CS.SpineClick)

-----------------------------------------------------------------
---@class LFormationObject
local LFormationObject = LxClass("LFormationObject", nil)
-----------------------------------------------------------------

function LFormationObject:LFormationObject()
	self._objKey = nil
	self._formationPos = nil
	---@type LDisplaySpine
	self._displaySpine = nil

	self._delayShow = nil

	self._side = 1

	self._loadedFunc = nil

	self._bEnableTouch = true

	self._showTime = 1
	self._interValTime = 0
end


function LFormationObject:CreateObject(parentTrans,spineName,scale,func, bloodData)
	local dp = LDisplaySpine:New()
	self._displaySpine = dp
	self._bloodData = bloodData

	self._loadedFunc = func

	dp:CreateSpine(parentTrans, spineName)
	dp:SetScale(scale)

	dp:SetLoadedFunction(function()
		self:OnLoaded()
	end)
end

function LFormationObject:OnLoaded()
	self:ModifyTopNode()
	self:InitClickCom()
	self:CreateBloodStick()
	self:UpdateChangeStatus()
	local func = self._loadedFunc
	if func then
		func()
	end
	if not self._delayShow then
		--self._showTime = 0.05
		--self._interValTime = 0.05
		self:ShowBirth()
	end
end
-----------------------------------------------------------------
--点击控件创建
function LFormationObject:InitClickCom()
	if not self:IsValid() then return end

	local spineTrans = self._displaySpine:GetSpineTrans()
	local spineClick = spineTrans:GetComponent(typeSpineClick)
	if not spineClick then
		spineClick = spineTrans.gameObject:AddComponent(typeSpineClick)
	end
	if not self._bEnableTouch then
		spineClick.enabled = false
	end
	self._spineClickCom = spineClick
end

function LFormationObject:GetClickCom()
	return self._spineClickCom
end

function LFormationObject:EnableTouch(bEnable)
	if self._bEnableTouch == bEnable then return end

	self._bEnableTouch = bEnable

	if not self:IsValid() then return end

	if self._spineClickCom then
		self._spineClickCom.enabled = bEnable
	end
end
