--血条创建
function LFormationObject:CreateBloodStick()
	if not self:IsValid() then return end
	if self._bloodStick then return end

	local bloodData = self._bloodData
	if not bloodData then return end

	-- 【C宠物系统】删掉宠物系统相关
	-- if bloodData.type == "pet" then
	-- 	self:CreatePetBloodStick(bloodData)
	-- 	return
	-- end

	local level = bloodData.level
	local isResonance = bloodData.isResonance
	local race = bloodData.race
	--local pos = bloodData.pos
	local isLeft = bloodData.isLeft
	local curHp = bloodData.curHp
	local maxHp = bloodData.maxHp

	local barType = isLeft and 1 or 2
	--local index  = isLeft and 1 or 2

	local bloodStick = LBloodStick:New()
	local dpTarns = self._displaySpine:GetDisplayTrans()
	local topNode = CS.FindTrans(dpTarns,"TopNode")
	local nowPos = dpTarns.position

	local heroData = {
		index = 2,
		race = race,
		level = level,
		isResonance = isResonance,
	}
	if bloodData.power then
		heroData.index = 3
		heroData.power = bloodData.power
	end

	bloodStick:CreateBloodStick(barType,maxHp,curHp,heroData)
	bloodStick:SetHeroTrans(dpTarns,topNode.position - nowPos)
	bloodStick:SetVisible(not self._delayShow)

	self._bloodStick = bloodStick

	bloodStick:StartLoad()
end

