function LFormationObject:SetBloodStickVisible(bVisible)
	if not self._bloodStick then return end

	self._bloodStick:SetVisible(bVisible)
end

function LFormationObject:SetDelayShow()
	self._delayShow = true
	self._showTime = 1
	self._interValTime = 0
end

function LFormationObject:DoDelayShow()
	self._delayShow = nil
	self:ShowBirth()
end

function LFormationObject:ShowBirth()
	if not self:IsValid() then return end

	self:KillBirthTween()

	self:SetVisible(true)

	local tweenSeq = YXTween.TweenSequenceIns()
	self._displaySpine:SetAlpha(0)
	local showtime = self._showTime
	local alphaTween = YXTween.TweenFloat(0,1,showtime * 0.5,function (value)
		self._displaySpine:SetAlpha(value)
	end):SetEase(DG.Tweening.Ease.InSine)

	if self._interValTime > 0 then
		tweenSeq:AppendInterval(self._interValTime)
	end
	tweenSeq:Append(alphaTween)
	tweenSeq:OnComplete(function()
		self._birthTween = nil
		self._delayShow = nil
		self:SetBloodStickVisible(true)
	end)

	self._birthTween = tweenSeq
	tweenSeq:PlayForward()
end

function LFormationObject:KillBirthTween()
	if self._birthTween then
		self._birthTween:Kill(false)
		self._birthTween = nil
	end
end

function LFormationObject:StartLoad()
	self._displaySpine:StartLoad()
end

-----------------------------------------------------------------
function LFormationObject:IsDestroy()
	return self._isDestroy
end

function LFormationObject:Destroy()
	self:KillBirthTween()

	if self._displaySpine then
		self._displaySpine:Destroy()
	end
	if self._bloodStick then
		self._bloodStick:Destroy()
	end

	table.removeall(self)
	self._isDestroy = true
end

