function LFormationObject:IsValid()
	if self:IsDestroy() then return false end
	if not self._displaySpine then return false end

	return self._displaySpine:IsDpValid()
end

function LFormationObject:GetDisplayObject()
	return self._displaySpine
end

function LFormationObject:GetDisplayTrans()
	if not self:IsValid() then return end

	return self._displaySpine:GetDisplayTrans()
end

function LFormationObject:MoveLocalPosition(pos)
	local tran = self:GetDisplayTrans()
	if tran then
		tran.localPosition = tran.localPosition + pos
	end
end

function LFormationObject:ResetPos()
	local tran = self:GetDisplayTrans()
	if tran then
		tran.localPosition = Vector3.zero
	end
end

function LFormationObject:SetVisible(bVisible)
	if not self._displaySpine then return end

	self._displaySpine:SetVisible(bVisible)
end

function LFormationObject:SetDirection(isInLeft,needFlip)
	if not self._displaySpine then return end
	
	local flip = not isInLeft and needFlip
	self._displaySpine:SetFlipX(flip)

end

function LFormationObject:ModifyTopNode()
	if self._side == LFightConst.ACTON_TEAM_B then
		local topNode,defaultPos = self._displaySpine:GetTopNodeInfo()
		printInfoN(string.format("x %s,y %s,z %s",defaultPos.x,defaultPos.y,defaultPos.z))
		local pos = Vector3.New(-defaultPos.x,defaultPos.y,0)
		topNode.localPosition = pos
	end
end

function LFormationObject:SetClickFunc(func)
	self._onClickFunc = func
end

function LFormationObject:CallClickFunc()
	if self._onClickFunc then
		self._onClickFunc(self)
	end
end

function LFormationObject:SetChangeStatus(status)
	self._changeStatus = status
	self:UpdateChangeStatus()
end

function LFormationObject:UpdateChangeStatus()
	if self._changeStatus and self._displaySpine then
		self._displaySpine:SetChangeStatus(self._changeStatus)
	end
end


return LFormationObject